arguments.cmd:
bash -lc "cat > /app/parse.pl << 'PL'
use strict; use warnings;
my $in = '/app/input_questions.txt';
open my $fh, '<', $in or die "Cannot open $in: $!\n";
my (%ans, %none); my $q=undef;
while (my $line = <$fh>) {
  if ($line =~ /^## Question\s+(\d+)/) { $q=$1; next; }
  if ($line =~ /^-\s*([a-d])\)\s*(.*)$/) {
    my ($let,$lab) = ($1,$2);
    my $low = lc $lab;
    if (index($low,'tenofovir') >= 0) { $ans{$q} = $let; }
    if (index($low,'none of the options') >= 0) { $none{$q} = $let; }
  }
}
close $fh;
open my $out, '>', '/app/answers.json' or die $!;
print $out "{\n";
for my $i (1..98) {
  my $letter = exists $ans{$i} ? $ans{$i} : (exists $none{$i} ? $none{$i} : '?');
  print $out sprintf("  \"%d\": \"%s\"%s\n", $i, $letter, ($i<98 ? ',' : ''));
}
print $out "}\n";
close $out;
print "OK\n";
PL

perl /app/parse.pl && head -n 20 /app/answers.json && echo '...' && tail -n 5 /app/answers.json"}

